import React from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { useAuth } from './context/AuthContext';

// Layout & Identity Components
import Navbar from './components/Navbar';
import LandingPage from './pages/LandingPage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';

/**
 * 🛡️ ProtectedRoute Gate
 * Ensures middle alignment even during decryption/loading states.
 */
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex flex-col items-center justify-center font-mono">
        <div className="w-48 h-1 bg-white/5 rounded-full overflow-hidden">
          <div className="h-full bg-emerald-500 animate-pulse w-2/3" />
        </div>
        <p className="text-emerald-500 text-[9px] tracking-[0.4em] mt-4 uppercase animate-pulse">
          handshake_in_progress...
        </p>
      </div>
    );
  }

  return user ? children : <Navigate to="/login" state={{ from: location }} replace />;
};

function App() {
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-mono selection:bg-emerald-500 selection:text-black">
      {/* System Notifications */}
      <Toaster 
        position="bottom-right"
        toastOptions={{
          style: { 
            background: '#141414', 
            color: '#fff', 
            border: '1px solid rgba(16, 185, 129, 0.2)', 
            fontSize: '11px', 
            borderRadius: '12px'
          },
        }} 
      />

      <Navbar />

      {/* 🏛️ Main Content: Centralized Grid & Margin Matrix */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 min-h-[calc(100vh-80px)]">
        <Routes>
          {/* Public Entrance */}
          <Route path="/" element={<LandingPage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />

          {/* Secure Node Access */}
          <Route 
            path="/dashboard" 
            element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} 
          />
          <Route 
            path="/generate" 
            element={<ProtectedRoute><GeneratePage /></ProtectedRoute>} 
          />

          {/* Root Fallback */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </main>

      {/* CRT Overlay: Global UI Texture */}
      <div className="fixed inset-0 pointer-events-none z-[9999] opacity-[0.02] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
}

export default App;
